   829	            .enumerate()
   830	            .filter_map(|(index, spec)| (!spec.schedule_rules.is_empty()).then_some(index))
   831	            .collect();
   832	        let mut schedule_aggregate_indices_by_rule =
   833	            vec![Vec::new(); self.model.transitions().len()];
   834	        for (index, spec) in self.aggs.iter().enumerate() {
   835	            if let Some(rule_id) = spec.schedule_rules.first() {
   836	                let rule_index = usize::try_from(*rule_id)
