 801	    fn emit(self) -> Result<GeneratedCuda, CudaError> {
 802	        let mut out = String::new();
 803	        writeln!(
 804	            out,
 805	            "// Generated by sembla-cuda {}. DO NOT EDIT.",
 806	            env!("CARGO_PKG_VERSION")
 807	        )
 808	        .unwrap();
 809	        let model_name_sha256 = hex(Sha256::digest(self.model.model().name.as_bytes()).as_slice());
 810	        writeln!(out, "// model-name-sha256: {model_name_sha256}").unwrap();
 811	        out.push_str(PRELUDE);
 812	        self.emit_input_helpers(&mut out)?;
 813	        self.emit_aggregate_kernel(&mut out)?;
 814	        let transition_kernels = self.emit_transition_kernels(&mut out)?;
 815	        self.emit_error_check_kernel(&mut out);
 816	        self.emit_resolve_kernel(&mut out)?;
 817	        self.emit_apply_kernel(&mut out)?;
 818	        self.emit_output_kernel(&mut out)?;
 819	        out.push_str(PHILOX_TEST_KERNEL);
 820	        let source_sha256 = hex(Sha256::digest(out.as_bytes()).as_slice());
 821	        let aggregate_group_tables = self
 822	            .aggs
 823	            .iter()
 824	            .map(|spec| self.global_table(spec.box_index, spec.group_table_index))
 825	            .collect();
 826	        let schedule_aggregate_indices = self
 827	            .aggs
 828	            .iter()
 829	            .enumerate()
 830	            .filter_map(|(index, spec)| (!spec.schedule_rules.is_empty()).then_some(index))
 831	            .collect();
 832	        let mut schedule_aggregate_indices_by_rule =
 833	            vec![Vec::new(); self.model.transitions().len()];
 834	        for (index, spec) in self.aggs.iter().enumerate() {
 835	            if let Some(rule_id) = spec.schedule_rules.first() {
 836	                let rule_index = usize::try_from(*rule_id)
 837	                    .map_err(|_| codegen("rule id exceeds host index width"))?;
 838	                schedule_aggregate_indices_by_rule[rule_index].push(index);
 839	            }
 840	        }
 841	        let effect_aggregate_indices = self
 842	            .aggs
 843	            .iter()
 844	            .enumerate()
 845	            .filter_map(|(index, spec)| {
 846	                (spec.schedule_rules.is_empty() && !spec.effect_rules.is_empty()).then_some(index)
 847	            })
 848	            .collect();
 849	        let output_aggregate_indices = self
 850	            .aggs
 851	            .iter()
 852	            .enumerate()
 853	            .filter_map(|(index, spec)| spec.output_use.then_some(index))
 854	            .collect();
 855	        Ok(GeneratedCuda {
 856	            source: out,
 857	            source_sha256,
 858	            transition_kernels,
 859	            aggregate_group_tables,
 860	            schedule_aggregate_indices,
 861	            schedule_aggregate_indices_by_rule,
 862	            effect_aggregate_indices,
 863	            output_aggregate_indices,
 864	        })
 865	    }
