 867	    fn emit_input_helpers(&self, out: &mut String) -> Result<(), CudaError> {
 868	        for (index, spec) in self.inputs.iter().enumerate() {
 869	            writeln!(out, "__device__ __forceinline__ {} sembla_input_{index}(const unsigned char* inputs, const unsigned long long* input_offsets, const unsigned long long* input_counts, const unsigned char* params, unsigned char* error) {{", spec.ty.cuda()).unwrap();
 870	            let port = self.port(spec.box_index, spec.port_index);
 871	            let selected = if let Some(filter) = &spec.agg.filter {
 872	                self.render(
 873	                    filter,
 874	                    Rows::Input {
 875	                        box_index: spec.box_index,
 876	                        port_index: spec.port_index,
 877	                    },
 878	                    Some(&Ty::Bool),
 879	                    "state",
 880	                    "row",
 881	                )?
 882	                .0
 883	            } else {
 884	                "1".to_owned()
 885	            };
 886	            // The CPU evaluates the complete filter column before reducing.
 887	            writeln!(out, "  for (unsigned long long row = 0; row < input_counts[{port}]; ++row) {{ (void)({selected}); if (*error) return ({})0; }}", spec.ty.cuda()).unwrap();
 888	            match &spec.agg.op {
 889	                AggOp::Count => {
 890	                    writeln!(out, "  long long result = 0LL;\n  for (unsigned long long row = 0; row < input_counts[{port}]; ++row) {{ int selected = {selected}; if (*error) return 0LL; if (selected) {{ result = sembla_add_i64(result, 1LL, error); if (*error) return 0LL; }} }}\n  return result;\n}}").unwrap();
 891	                }
 892	                AggOp::Sum { value } => {
 893	                    let rendered = self
 894	                        .render(
 895	                            value,
 896	                            Rows::Input {
 897	                                box_index: spec.box_index,
 898	                                port_index: spec.port_index,
 899	                            },
 900	                            Some(&spec.ty),
 901	                            "state",
 902	                            "row",
 903	                        )?
 904	                        .0;
 905	                    writeln!(out, "  {} result = ({})0;\n  for (unsigned long long row = 0; row < input_counts[{port}]; ++row) {{ int selected = {selected}; if (*error) return ({})0; if (selected) {{ {} value = ({})({rendered}); if (*error) return ({})0;", spec.ty.cuda(), spec.ty.cuda(), spec.ty.cuda(), spec.ty.cuda(), spec.ty.cuda(), spec.ty.cuda()).unwrap();
 906	                    if spec.ty == Ty::Int {
 907	                        out.push_str(" result = sembla_add_i64(result, value, error);");
 908	                    } else {
 909	                        out.push_str(" result = result + (double)value;");
 910	                    }
 911	                    writeln!(
 912	                        out,
 913	                        " if (*error) return ({})0; }} }}\n  return result;\n}}",
 914	                        spec.ty.cuda()
 915	                    )
 916	                    .unwrap();
 917	                }
 918	            }
 919	        }
 920	        Ok(())
 921	    }
