 923	    fn emit_aggregate_kernel(&self, out: &mut String) -> Result<(), CudaError> {
 924	        out.push_str("\nextern \"C\" __global__ void sembla_reset_status(unsigned long long* status, unsigned char* aggregate_errors, unsigned long long error_count) {\n  if (blockIdx.x != 0 || threadIdx.x != 0) return;\n  status[0] = 0ULL; status[1] = 0ULL; status[2] = 0ULL; status[3] = 0ULL;\n  for (unsigned long long i = 0; i < error_count; ++i) aggregate_errors[i] = 0U;\n}\n");
