 926	        for (index, spec) in self.aggs.iter().enumerate() {
 927	            if !spec.schedule_rules.is_empty() {
 928	                continue;
 929	            }
 930	            for rule_id in &spec.effect_rules {
 931	                let validated = self
 932	                    .model
 933	                    .transitions()
 934	                    .iter()
 935	                    .find(|transition| transition.rule_id == *rule_id)
 936	                    .expect("aggregate effect rule is validated");
