 797	    model: &ValidatedModel,
 798	    snapshot: &Snapshot<'_>,
 799	    params: &ParamEnv,
 800	) -> Result<Vec<InputTable>, TickError> {
 801	    let mut inputs = model
 802	        .model()
 803	        .boxes
 804	        .iter()
 805	        .flat_map(|model_box| {
 806	            model_box
 807	                .inputs
 808	                .iter()
 809	                .map(|input| InputTable::empty(&model_box.name, &input.name, &input.schema))
 810	        })
 811	        .collect::<Vec<_>>();
 812	    for wire in &model.model().wires {
 813	        let source_box = model
 814	            .model()
 815	            .boxes
 816	            .iter()
 817	            .find(|model_box| model_box.name == wire.from.r#box)
 818	            .expect("validated wire source box disappeared");
 819	        let output = source_box
 820	            .outputs
 821	            .iter()
 822	            .find(|output| output.name == wire.from.port)
 823	            .expect("validated wire source port disappeared");
 824	        let built = build_output(model, snapshot, params, source_box, output)?;
 825	        let destination = inputs
 826	            .iter_mut()
 827	            .find(|input| input.box_name == wire.to.r#box && input.port_name == wire.to.port)
 828	            .expect("validated wire destination disappeared");
 829	        destination.row_count = built.row_count;
 830	        destination.columns = built.columns;
 831	    }
 832	    Ok(inputs)
